def find_first_non_repeating(s):
    # Step 1: Build a frequency dictionary
    counts = {}
    for char in s:
        counts[char] = counts.get(char, 0) + 1

    # Step 2: Traverse the string to find the first char with count 1
    for char in s:
        if counts[char] == 1:
            return char

    return None

# Example Usage
input_str = "GeeksForGeeks"
result = find_first_non_repeating(input_str)
print(f"Input: {input_str}")
print(f"Output: {result}")
